COPY public.hotels (id, name, location, region, type, rating, price_tier, amenities, image, description, featured, created_at, updated_at, created_by, slug, full_description, highlights, gallery, rooms) FROM stdin;
b9758d4f-3f40-4e58-bbcb-2004899b6137	Waldorf Astoria Cairo Heliopolis 	Egypt 	Cairo & Giza	Luxury Hotel	5	$$$$	{"24-hour Concierge Service","Spa & Wellness Center","Outdoor Swimming Pool","Pool Cabanas","Fine Dining Restaurant (Brasserie Ayda)","Bar & Lounge (Bar Raa)","Poolside Bar","Grand Ballroom & Event Spaces","Business Center","Fitness Center","24-hour Room Service","Complimentary High-Speed WiFi","Airport Shuttle Service","Valet Parking","Laundry & Dry Cleaning","Meeting Rooms"}	https://iluxuryegypt.com/api/assets/uploads/8da9ad41-48b8-479a-8035-cf9fe2116c2d.webp	Experience unparalleled luxury at Waldorf Astoria Cairo Heliopolis a magnificent five-star retreat in historic Heliopolis, moments from Cairo International Airport. Featuring 252 elegantly appointed rooms and suites with personalized service, world-class dining, and exclusive amenities.	t	2026-02-08 03:24:38.29805	2026-02-08 03:24:38.29805	73480e9b-4af4-4782-9d1d-a7269fc854e2	waldorf-astoria-cairo-heliopolis	\n\nExperience unparalleled luxury at Waldorf Astoria Cairo Heliopolis, a distinguished five-star retreat near Cairo International Airport. Featuring 252 elegant rooms and suites with floor-to-ceiling windows, this iconic hotel offers refined Mediterranean dining at Brasserie Ayda, artisan cocktails at Bar Raa, restorative spa treatments, and personalized concierge service. Perfectly positioned near Khan El Khalili Bazaar and the Grand Egyptian Museum, Waldorf Astoria Cairo Heliopolis blends timeless Egyptian heritage with legendary hospitality.	{"Spectacular atrium lobby with palm trees and clock fountain","252 luxurious rooms and suites with floor-to-ceiling windows","Brasserie Ayda - refined Mediterranean dining","Bar Raa - 1920s-inspired cocktail lounge with live jazz","Stunning poolside bar and exclusive cabanas","Restorative spa with Thai massage and aromatherapy","Grand Ballroom for up to 1,600 guests","Personalized concierge service","Minutes from Cairo International Airport","Near Khan El Khalili Bazaar and Grand Egyptian Museum","Exclusive Rosetta Club access in select rooms"}	{https://iluxuryegypt.com/api/assets/uploads/ac5be971-d25f-4e73-9a39-b1e33745f26d.jpg,https://iluxuryegypt.com/api/assets/uploads/9406d82f-60f4-457b-9da3-d43bd15a4fb1.jpg,https://iluxuryegypt.com/api/assets/uploads/6118e566-b166-4441-9db0-a162d97da1c1.jpg,https://iluxuryegypt.com/api/assets/uploads/f3a77512-372a-4f72-9e60-88cd8e0faf2d.jpg,https://iluxuryegypt.com/api/assets/uploads/793e90c9-12c2-43f2-9e4c-3fa3710bd785.jpg,https://iluxuryegypt.com/api/assets/uploads/78da1b32-3beb-46f1-af48-63f9364d6286.jpg,https://iluxuryegypt.com/api/assets/uploads/7034f25d-7a9d-44a2-9e7c-eb9907528d01.jpg,https://iluxuryegypt.com/api/assets/uploads/3b321c9b-d04b-4a5c-ba60-0f1e297d7c5f.jpg,https://iluxuryegypt.com/api/assets/uploads/80215ac3-9cf9-4ed7-acc9-3542fdcc39fc.jpg,https://iluxuryegypt.com/api/assets/uploads/89bafe49-b8e2-49b9-9603-e10632602475.jpg,https://iluxuryegypt.com/api/assets/uploads/d0ef96b2-bd77-476f-9769-0c4e6c91cf86.jpg,https://iluxuryegypt.com/api/assets/uploads/c0c23ee2-0031-48c8-b207-21e2f2b23c55.jpg,https://iluxuryegypt.com/api/assets/uploads/60a9bf6c-d425-411e-9710-15104c3fa16a.jpg,https://iluxuryegypt.com/api/assets/uploads/31eec316-2e91-4e40-a6a8-b47f66d9f0c2.jpg,https://iluxuryegypt.com/api/assets/uploads/7796a921-7130-4f22-bd49-922f9af374e0.jpg,https://iluxuryegypt.com/api/assets/uploads/5e4f937a-0252-47e2-a47a-6d9f054a6ae6.jpg}	[{"id": "room-1770510838707", "name": "Two Double Beds Deluxe Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/88c8aaf7-5fc4-4d0a-b750-e563aa401441.jpg", "https://iluxuryegypt.com/api/assets/uploads/bac0a3fa-7436-47a3-9e36-1d3bf55391e5.jpg"], "amenities": ["Two Double Beds", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Bathrobe and slippers", "In-room safe", "Air conditioning", "24-hour housekeeping"], "occupancy": 2, "description": "Spacious and refined, this Deluxe Room offers two plush double beds and expansive floor-to-ceiling windows that fill the space with natural light. Begin your day with a fresh espresso, relax with your favorite program on the 55-inch HDTV, or unwind under the elegant rain shower. The contemporary décor and thoughtful details create a serene and comfortable ambiance.\\n\\n\\n\\n\\n\\n\\n"}, {"id": "room-1770510840159", "name": "King Deluxe Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/9b5d40b3-925d-4d0a-bee1-e7522670915f.jpg", "https://iluxuryegypt.com/api/assets/uploads/9406d82f-60f4-457b-9da3-d43bd15a4fb1.jpg"], "amenities": ["King-sized bed", "24-hour housekeeping", "Air conditioning", "In-room safe", "Bathrobe and slippers", "Rain shower", "Minibar", "Complimentary WiFi", "Espresso machine", "55-inch HDTV"], "occupancy": 2, "description": "Elegant and modern, the King Deluxe Room blends luxury and comfort with floor-to-ceiling windows and sophisticated furnishings. Enjoy freshly brewed espresso while watching your 55-inch HDTV or unwind in the stylish marble bathroom featuring a soothing rain shower.\\n\\n"}, {"id": "room-1770510841368", "name": "Two Double Beds Premier Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/793e90c9-12c2-43f2-9e4c-3fa3710bd785.jpg", "https://iluxuryegypt.com/api/assets/uploads/f3a77512-372a-4f72-9e60-88cd8e0faf2d.jpg"], "amenities": ["24-hour housekeeping", "Air conditioning", "In-room safe", "City view", "Rain shower", "Minibar", "Complimentary WiFi", "Espresso machine", "55-inch HDTV", "Two Double Beds"], "occupancy": 2, "description": "The Premier Room offers refined comfort and understated sophistication. With two plush double beds, a contemporary design, and expansive floor-to-ceiling windows, this room is a peaceful retreat. Enjoy your favorite beverage from the espresso machine and unwind with a 55-inch HDTV or in the elegant marble bathroom featuring a rain shower.\\n\\n\\n"}, {"id": "room-1770510845233", "name": "King Premier Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/8c2b2cc9-5be5-478b-8548-9e41764d7f7d.jpg", "https://iluxuryegypt.com/api/assets/uploads/78da1b32-3beb-46f1-af48-63f9364d6286.jpg"], "amenities": ["24-hour housekeeping", "Air conditioning", "In-room safe", "City view", "Rain shower", "Minibar", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "King-sized bed"], "occupancy": 2, "description": "A haven of calm sophistication, the King Premier Room combines elegant décor with natural light from floor-to-ceiling windows. The plush king bed ensures restful sleep, while the marble bathroom with a rain shower provides a spa-like retreat.\\n\\n\\n"}, {"id": "room-1770510846371", "name": "King Premier Room with Pool View", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/3b321c9b-d04b-4a5c-ba60-0f1e297d7c5f.jpg", "https://iluxuryegypt.com/api/assets/uploads/7034f25d-7a9d-44a2-9e7c-eb9907528d01.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Pool view", "In-room safe", "Air conditioning", "24-hour housekeeping"], "occupancy": 2, "description": "This beautifully designed Premier Room with Pool View offers serenity and sophistication. The plush king-sized bed and expansive floor-to-ceiling windows overlook the calming pool. Elegant décor and contemporary furnishings create a refined yet welcoming ambiance, while the marble bathroom with a rain shower ensures pure relaxation."}, {"id": "room-1770510847889", "name": " King Premier Room with Terrace and Pool View", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/80215ac3-9cf9-4ed7-acc9-3542fdcc39fc.jpg", "https://iluxuryegypt.com/api/assets/uploads/3ed07671-1490-4dea-8a35-963e599ee5c2.jpg"], "amenities": ["Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Private balcony with pool view", "In-room safe", "Air conditioning", "24-hour housekeeping"], "occupancy": 2, "description": "An elevated retreat, the King Premier Room with Terrace and Pool View invites you to relax both indoors and outdoors. Enjoy serene pool views from your private furnished balcony, or unwind in your spacious interiors featuring chic furnishings and contemporary design. The elegant marble bathroom offers a luxurious rain shower and premium amenities."}, {"id": "room-1770510850361", "name": "King Premier Room Botanical View", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/92b72745-1c60-44f2-bb8f-28dfcbe1176b.jpg", "https://iluxuryegypt.com/api/assets/uploads/fe8f9c19-dfa1-4ba0-a2bc-09eba8bd83f0.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Botanical garden view", "In-room safe", "Air conditioning", "24-hour housekeeping"], "occupancy": 2, "description": "Bask in natural tranquility in the King Premier Room with Botanical View, where elegant interiors meet lush garden scenery. The light-filled room features a plush king-sized bed, stylish furnishings, and calming décor. Refresh in the marble bathroom with a rain shower and unwind with your espresso or favorite program on the 55-inch HDTV."}, {"id": "room-1770510851392", "name": "Two Double Beds Rosetta Club Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/59469cf6-6922-4dae-b99d-0d81ac86b2f7.jpg", "https://iluxuryegypt.com/api/assets/uploads/910f04c0-b32d-4886-9d26-53730ba67046.jpg"], "amenities": ["Two Double Beds", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Exclusive Club Lounge access", "In-room safe", "Air conditioning", "24-hour housekeeping"], "occupancy": 2, "description": "The Rosetta Club Room offers an elevated stay experience with exclusive access to the Waldorf Astoria Club — including complimentary breakfast, drinks, and light refreshments throughout the day. The room features two double beds, elegant décor, and floor-to-ceiling windows for abundant natural light. The marble bathroom is fitted with a rain shower and premium amenities for total relaxation."}, {"id": "room-1770510852503", "name": "King Rosetta Club Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/89bafe49-b8e2-49b9-9603-e10632602475.jpg", "https://iluxuryegypt.com/api/assets/uploads/e1feb93e-a477-4d83-b606-a17e36ec1263.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Exclusive Club Lounge access", "In-room safe", "Air conditioning", "24-hour housekeeping"], "occupancy": 2, "description": "Experience refined luxury in the King Rosetta Club Room, offering exclusive access to the Rosetta Club with complimentary breakfast, drinks, and light snacks throughout the day. The spacious interiors feature elegant modern décor, a plush king-sized bed, and floor-to-ceiling windows that bathe the room in natural light. Refresh in the marble bathroom equipped with a rain shower, and unwind with your favorite show on the 55-inch HDTV."}, {"id": "room-1770510853322", "name": "King Rosetta Club Accessible Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/d0ef96b2-bd77-476f-9769-0c4e6c91cf86.jpg", "https://iluxuryegypt.com/api/assets/uploads/c0c23ee2-0031-48c8-b207-21e2f2b23c55.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Roll-in shower (accessible)", "Exclusive Club Lounge access", "Mobility accessible layout", "In-room safe", "24-hour housekeeping"], "occupancy": 2, "description": "Designed for accessibility without compromise on style, the King Rosetta Club Accessible Room offers both comfort and convenience. Featuring a roll-in shower and accessible layout, it maintains the sophistication of the Waldorf Astoria with light, spacious interiors and floor-to-ceiling windows. Guests enjoy exclusive Rosetta Club access, including complimentary breakfast, drinks, and snacks."}, {"id": "room-1770510854430", "name": "King Rosetta Club Room with Pool View", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/a8e849a0-5bbd-410c-b7d7-3ae097ff0782.jpg", "https://iluxuryegypt.com/api/assets/uploads/0e81d600-0a55-4417-a3ad-d41ec0d18416.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Pool view", "Exclusive Club Lounge access", "In-room safe", "24-hour housekeeping"], "occupancy": 2, "description": "Enjoy a serene escape in the King Rosetta Club Room with Pool View, combining elegant comfort with privileged Rosetta Club access. The soothing pool view through expansive floor-to-ceiling windows adds a calming atmosphere to this sophisticated retreat. Guests can enjoy complimentary breakfast, drinks, and snacks in the exclusive Club Lounge, or unwind in the marble bathroom featuring a luxurious rain shower."}, {"id": "room-1770510855483", "name": " King Deluxe One Bedroom Suite", "size": "84 sq. m / 904 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/31eec316-2e91-4e40-a6a8-b47f66d9f0c2.jpg", "https://iluxuryegypt.com/api/assets/uploads/08d6bfcd-ebf4-4a38-8528-ef0e4f8df8d3.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Separate living room", "Exclusive Club Lounge access", "In-room safe", "24-hour housekeeping"], "occupancy": 2, "description": "Step into timeless elegance in the King Deluxe One Bedroom Suite, offering a spacious living area and private bedroom for an indulgent stay. Enjoy exclusive access to the Rosetta Club, where complimentary breakfast, drinks, and snacks are served throughout the day. Modern comforts include a 55-inch HDTV, espresso machine, and WiFi, while the elegant bathroom features a luxurious rain shower and premium amenities."}, {"id": "room-1770510856517", "name": " King Deluxe One Bedroom Suite with Terrace", "size": "84 sq. m / 904 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/7796a921-7130-4f22-bd49-922f9af374e0.jpg", "https://iluxuryegypt.com/api/assets/uploads/ef5655a9-6882-4cfa-89b9-07b73a6f5d93.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Rain shower", "Separate living room", "Private balcony", "Exclusive Club Lounge access", "24-hour housekeeping"], "occupancy": 2, "description": "Experience refined luxury in this elegant one-bedroom suite with a private furnished balcony offering tranquil views and outdoor seating. The suite includes a separate living room, providing extra space to relax or entertain. Guests enjoy exclusive access to the Rosetta Club, offering complimentary breakfast, drinks, and snacks. Inside, the contemporary décor, plush furnishings, and warm lighting create a serene and sophisticated ambiance."}, {"id": "room-1770510860521", "name": "Presidential Suite", "size": "163 sq. m / 1,754 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/42259593-7072-4d55-96fa-d4516b0151ce.jpg", "https://iluxuryegypt.com/api/assets/uploads/a56bc994-ecbd-4778-8614-df24f188d1f6.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Whirlpool bath", "Full kitchen", "Separate living and dining areas", "Exclusive Club Lounge access", "24-hour housekeeping"], "occupancy": 2, "description": "The Presidential Suite represents the pinnacle of Waldorf Astoria luxury. This expansive residence offers a private bedroom with a plush king-sized bed, a grand living room, a full kitchen, and a dining area for intimate gatherings. Guests enjoy exclusive Club access, including complimentary breakfast, drinks, and snacks. The elegant bathroom features a rain shower and premium amenities for complete relaxation."}, {"id": "room-1770510862958", "name": "King Deluxe Accessible Room", "size": "44 sq. m / 473 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/0a8712ad-1163-439b-8f2a-cc7efed0cd91.jpg", "https://iluxuryegypt.com/api/assets/uploads/0a8712ad-1163-439b-8f2a-cc7efed0cd91.jpg"], "amenities": ["King-sized bed", "55-inch HDTV", "Espresso machine", "Complimentary WiFi", "Minibar", "Roll-in shower (accessible)", "Mobility accessible layout", "Lowered fixtures", "In-room safe", "24-hour housekeeping"], "occupancy": 2, "description": "Thoughtfully designed for accessibility and comfort, this spacious room features one king-sized bed and a roll-in shower for ease of movement. The décor blends functionality with elegance, offering a relaxing space filled with natural light. Guests enjoy a 55-inch HDTV, espresso machine, and complimentary WiFi for a seamless stay."}, {"id": "room-1770510864158", "name": "Deluxe Family Connecting Room", "size": "88 sq. m / 947 sq. ft.", "images": ["https://iluxuryegypt.com/api/assets/uploads/eb51b976-6432-4ece-87d0-42799a5d2b8e.jpg", "https://iluxuryegypt.com/api/assets/uploads/ac5bd96e-3614-4229-bc92-6bd9b1767ca2.jpg"], "amenities": ["King bed + Two Double Beds", "Espresso machines", "Complimentary WiFi", "Minibar", "Two bathrooms with rain showers", "Two connecting bedrooms", "In-room safe", "Air conditioning", "24-hour housekeeping", "55-inch HDTVs (2 TVs)"], "occupancy": 2, "description": "Perfect for families, this connecting suite offers two spacious bedrooms — one with a king-sized bed and the other with two double beds. Each room includes a 55-inch HDTV, espresso machine, and an elegant bathroom with a luxurious rain shower. The sophisticated décor and floor-to-ceiling windows create a warm and inviting space ideal for family stays."}]
